export interface AssetConfig {
    id: string;
    type: 'image' | 'audio' | 'json' | 'text';
    url: string;
    loaded?: boolean;
    data?: unknown;
}

export class AssetManager {
    private engine: unknown;
    private assets: Map<string, AssetConfig> = new Map();
    private loadingPromises: Map<string, Promise<unknown>> = new Map();
    private basePath: string = '';
    private loaded: boolean = false;

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async initialize(): Promise<void> {
        console.log('📦 AssetManager 初始化...');
        this.loaded = true;
        console.log('✅ AssetManager 初始化完成');
    }

    setBasePath(path: string): void {
        this.basePath = path;
    }

    register(id: string, config: AssetConfig): void {
        this.assets.set(id, { ...config, loaded: false });
    }

    async load(id: string): Promise<unknown> {
        const asset = this.assets.get(id);
        if (!asset) {
            throw new Error(`Asset not found: ${id}`);
        }

        if (asset.loaded && asset.data) {
            return asset.data;
        }

        if (this.loadingPromises.has(id)) {
            return this.loadingPromises.get(id)!;
        }

        const promise = this.loadAsset(asset);
        this.loadingPromises.set(id, promise);

        try {
            const data = await promise;
            asset.data = data;
            asset.loaded = true;
            return data;
        } finally {
            this.loadingPromises.delete(id);
        }
    }

    private async loadAsset(asset: AssetConfig): Promise<unknown> {
        const url = this.basePath + asset.url;

        switch (asset.type) {
            case 'image':
                return this.loadImage(url);
            case 'audio':
                return this.loadAudio(url);
            case 'json':
                return this.loadJson(url);
            case 'text':
                return this.loadText(url);
            default:
                throw new Error(`Unknown asset type: ${asset.type}`);
        }
    }

    private loadImage(url: string): Promise<HTMLImageElement> {
        return new Promise((resolve, reject) => {
            const img = new Image();
            img.onload = () => resolve(img);
            img.onerror = () => reject(new Error(`Failed to load image: ${url}`));
            img.src = url;
        });
    }

    private loadAudio(url: string): Promise<HTMLAudioElement> {
        return new Promise((resolve, reject) => {
            const audio = new Audio();
            audio.oncanplaythrough = () => resolve(audio);
            audio.onerror = () => reject(new Error(`Failed to load audio: ${url}`));
            audio.src = url;
        });
    }

    private async loadJson(url: string): Promise<unknown> {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Failed to load JSON: ${url}`);
        }
        return response.json();
    }

    private async loadText(url: string): Promise<string> {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Failed to load text: ${url}`);
        }
        return response.text();
    }

    get<T = unknown>(id: string): T | undefined {
        const asset = this.assets.get(id);
        return asset?.data as T | undefined;
    }

    has(id: string): boolean {
        return this.assets.has(id);
    }

    isLoaded(id: string): boolean {
        const asset = this.assets.get(id);
        return asset?.loaded ?? false;
    }

    async loadAll(ids: string[]): Promise<Map<string, unknown>> {
        const results = new Map<string, unknown>();
        await Promise.all(ids.map(async (id) => {
            const data = await this.load(id);
            results.set(id, data);
        }));
        return results;
    }

    unload(id: string): void {
        const asset = this.assets.get(id);
        if (asset) {
            asset.data = undefined;
            asset.loaded = false;
        }
    }

    clear(): void {
        this.assets.clear();
        this.loadingPromises.clear();
    }
}

export default AssetManager;
